            isRelationPair(input) ? input[$internal].relation[$internal].trait : isRelation(input) ? input[$internal].trait : input
        ) as ExtractTraits<T>;
        return setModifierRelationPairs(createModifier(`added-${id}`, id, traits), inputs.filter(isRelationPair));
    };
}

